/**
 * MedX breakpoints theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Responsive breakpoints for warehouse tablet views.
 */
const BREAKPOINTS_TOKENS = Object.freeze({
  primary: { value: "theme-breakpoints-primary", scope: "theme" },
  secondary: { value: "theme-breakpoints-secondary", scope: "theme" },
  muted: { value: "theme-breakpoints-muted", scope: "theme" },
  accent: { value: "theme-breakpoints-accent", scope: "theme" },
  surface: { value: "theme-breakpoints-surface", scope: "theme" },
});

const BREAKPOINTS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const BREAKPOINTS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const breakpointsRegistry = new Map();
const BREAKPOINTS_listeners = new Set();
let BREAKPOINTS_seq = 0;

function createBreakpointsId(prefix = "medx-theme-breakpoints") {
  BREAKPOINTS_seq += 1;
  return `${prefix}-${BREAKPOINTS_seq}`;
}

function registerBreakpoints(config = {}) {
  const entryId = config.id ?? createBreakpointsId();
  const preset = BREAKPOINTS_PRESETS[config.preset ?? "default"] ?? BREAKPOINTS_PRESETS.default;
  const token = BREAKPOINTS_TOKENS[config.token ?? preset.token] ?? BREAKPOINTS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: BREAKPOINTS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  breakpointsRegistry.set(entryId, entry);
  notifyBreakpointsListeners("register", entry);
  return entry;
}

function updateBreakpoints(id, patch = {}) {
  const entry = breakpointsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyBreakpointsListeners("update", entry);
  return entry;
}

function resolveBreakpoints(id) {
  const entry = breakpointsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listBreakpointsEntries(filter = {}) {
  let items = Array.from(breakpointsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onBreakpointsEvent(listener) {
  BREAKPOINTS_listeners.add(listener);
  return () => BREAKPOINTS_listeners.delete(listener);
}

function notifyBreakpointsListeners(type, entry) {
  for (const listener of BREAKPOINTS_listeners) {
    try {
      listener({ type, entry, registrySize: breakpointsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:breakpoints] listener error", err.message);
    }
  }
}

function getBreakpointsMetrics() {
  const items = listBreakpointsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(BREAKPOINTS_TOKENS).length,
    presets: Object.keys(BREAKPOINTS_PRESETS).length,
  };
}

async function runMedxBreakpoints() {
  console.log("[medx:ui:theme:breakpoints] runtime initialized");
  console.log(`[medx:ui:theme:breakpoints] tokens=${Object.keys(BREAKPOINTS_TOKENS).length} presets=${Object.keys(BREAKPOINTS_PRESETS).length}`);

  const events = [];
  onBreakpointsEvent((e) => events.push(e.type));

  const domains = Object.keys(BREAKPOINTS_SUPPLY_CHAIN);
  const presets = Object.keys(BREAKPOINTS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerBreakpoints({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/breakpoints" },
    });
  }

  const first = listBreakpointsEntries()[0];
  if (first) updateBreakpoints(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getBreakpointsMetrics();
  const resolved = first ? resolveBreakpoints(first.id) : null;

  console.log(`[medx:ui:theme:breakpoints] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:breakpoints] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:breakpoints] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:breakpoints] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:breakpoints] bootstrap complete");
}

module.exports = runMedxBreakpoints;
